import{_ as t,o as i,c as a,ai as s}from"./chunks/framework.Df5W0LJX.js";const u=JSON.parse(`{"title":"I Automated My LinkedIn Publishing Pipeline with RSS and Buffer. Here's the Exact Stack.","description":"VitePress generates the RSS feed at build time. GitHub Actions deploys it. Buffer picks it up and posts to LinkedIn. Zero manual steps after the git push.","frontmatter":{"title":"I Automated My LinkedIn Publishing Pipeline with RSS and Buffer. Here's the Exact Stack.","date":"2026-05-11T00:00:00.000Z","description":"VitePress generates the RSS feed at build time. GitHub Actions deploys it. Buffer picks it up and posts to LinkedIn. Zero manual steps after the git push.","head":[["meta",{"property":"og:title","content":"I Automated My LinkedIn Publishing Pipeline with RSS and Buffer. Here's the Exact Stack."}],["meta",{"property":"og:description","content":"VitePress generates the RSS feed at build time. GitHub Actions deploys it. Buffer picks it up and posts to LinkedIn. Zero manual steps after the git push."}],["meta",{"property":"og:url","content":"https://vishnukarthik.me/blog/linkedin-rss-automation/"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://vishnukarthik.me/blog/VKP.png"}],["meta",{"name":"twitter:title","content":"I Automated My LinkedIn Publishing Pipeline with RSS and Buffer. Here's the Exact Stack."}],["meta",{"name":"twitter:description","content":"VitePress generates the RSS feed at build time. GitHub Actions deploys it. Buffer picks it up and posts to LinkedIn. Zero manual steps after the git push."}],["meta",{"name":"description","content":"VitePress generates the RSS feed at build time. GitHub Actions deploys it. Buffer picks it up and posts to LinkedIn. Zero manual steps after the git push."}],["meta",{"property":"article:published_time","content":"2026-05-11T00:00:00.000Z"}]]},"headers":[],"relativePath":"linkedin-rss-automation.md","filePath":"linkedin-rss-automation.md"}`),n={name:"linkedin-rss-automation.md"};function o(r,e,d,l,p,h){return i(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="i-automated-my-linkedin-publishing-pipeline-with-rss-and-buffer-here-s-the-exact-stack" tabindex="-1">I Automated My LinkedIn Publishing Pipeline with RSS and Buffer. Here&#39;s the Exact Stack. <a class="header-anchor" href="#i-automated-my-linkedin-publishing-pipeline-with-rss-and-buffer-here-s-the-exact-stack" aria-label="Permalink to “I Automated My LinkedIn Publishing Pipeline with RSS and Buffer. Here&#39;s the Exact Stack.”">​</a></h1><p>Every time I pushed a blog post to GitHub, I had the same ritual: copy the title, paste it into LinkedIn, rewrite the description to not sound robotic, add the URL, pick hashtags, schedule it, and close fourteen tabs. Twenty minutes for something that should take zero.</p><p>So I automated it.</p><hr><h2 id="the-architecture" tabindex="-1">The Architecture <a class="header-anchor" href="#the-architecture" aria-label="Permalink to “The Architecture”">​</a></h2><p>The pipeline is three moving parts stitched together at build time:</p><p><strong>VitePress → RSS feed → Buffer → LinkedIn</strong></p><p>No webhooks. No cron jobs. No third-party bots that will break in six months. Just a Vite plugin that runs during <code>npm run docs:build</code> and writes a <code>feed.xml</code> into the output directory alongside the rest of the static site.</p><hr><h2 id="the-rss-plugin" tabindex="-1">The RSS Plugin <a class="header-anchor" href="#the-rss-plugin" aria-label="Permalink to “The RSS Plugin”">​</a></h2><p>VitePress exposes a <code>buildEnd</code> Vite plugin hook. That&#39;s where the feed gets generated.</p><p>The plugin reads every <code>.md</code> file in the <code>docs/</code> directory, extracts frontmatter (<code>title</code>, <code>date</code>, <code>description</code>), strips markdown from the first paragraph for the excerpt, sorts by date descending, and serialises it to RSS 2.0 XML.</p><p>The output gets written to <code>docs/.vitepress/dist/feed.xml</code>. A GitHub Actions step copies it to <code>dist/blog/feed.xml</code> before the deploy, so it lands at <code>https://vishnukarthik.me/blog/feed.xml</code> — permanently, predictably, the same URL every time.</p><p>No runtime server. No API calls. Pure static generation.</p><hr><h2 id="open-graph-per-post" tabindex="-1">Open Graph Per Post <a class="header-anchor" href="#open-graph-per-post" aria-label="Permalink to “Open Graph Per Post”">​</a></h2><p>LinkedIn&#39;s link preview is determined by the Open Graph tags on the page at the time LinkedIn&#39;s crawler fetches it. VitePress&#39;s <code>transformPageData</code> hook runs during build and injects per-post OG tags into the <code>&lt;head&gt;</code>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>og:title       → frontmatter.title</span></span>
<span class="line"><span>og:description → frontmatter.description</span></span>
<span class="line"><span>og:url         → https://vishnukarthik.me/blog/{slug}/</span></span>
<span class="line"><span>og:type        → article</span></span>
<span class="line"><span>article:published_time → ISO 8601 date from frontmatter</span></span></code></pre></div><p>This means every post gets its own preview card on LinkedIn — not the site default.</p><hr><h2 id="github-actions" tabindex="-1">GitHub Actions <a class="header-anchor" href="#github-actions" aria-label="Permalink to “GitHub Actions”">​</a></h2><p>The deploy workflow now has one extra step between <code>docs:build</code> and <code>actions-gh-pages</code>:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Copy RSS feed into blog output</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  run</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cp docs/.vitepress/dist/feed.xml dist/blog/feed.xml</span></span></code></pre></div><p>That&#39;s it. The rest of the workflow is unchanged. Build, copy, deploy.</p><hr><h2 id="buffer-configuration" tabindex="-1">Buffer Configuration <a class="header-anchor" href="#buffer-configuration" aria-label="Permalink to “Buffer Configuration”">​</a></h2><p>Buffer&#39;s RSS Automation (available on Essentials and above) polls an RSS feed URL on a schedule and creates a draft — or auto-publishes — whenever a new <code>&lt;item&gt;</code> appears that it hasn&#39;t seen before.</p><p>Setup is four fields:</p><ol><li><strong>Feed URL</strong>: <code>https://vishnukarthik.me/blog/feed.xml</code></li><li><strong>Channel</strong>: LinkedIn personal profile</li><li><strong>Post template</strong>: <code>{title}\\n\\n{description}\\n\\n{link}\\n\\n#Technology #AI #TechStrategy</code></li><li><strong>Schedule</strong>: Buffer posts at your pre-configured best-time slot</li></ol><p>Buffer detects new items by tracking <code>&lt;guid&gt;</code> values. The <code>&lt;guid&gt;</code> in the feed is the full post URL, which is stable and unique. Once Buffer has seen a guid, it won&#39;t republish it — so there&#39;s no risk of duplicate posts from re-deployments.</p><hr><h2 id="the-post-template" tabindex="-1">The Post Template <a class="header-anchor" href="#the-post-template" aria-label="Permalink to “The Post Template”">​</a></h2><p>Buffer&#39;s template variables map directly to RSS fields:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Source</th></tr></thead><tbody><tr><td><code>{title}</code></td><td><code>&lt;title&gt;</code> — pulled from frontmatter</td></tr><tr><td><code>{description}</code></td><td><code>&lt;description&gt;</code> — frontmatter description or first-paragraph excerpt</td></tr><tr><td><code>{link}</code></td><td><code>&lt;link&gt;</code> — canonical post URL</td></tr></tbody></table><p>The template I use:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>{title}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{description}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Read → {link}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#AI #Technology #TechStrategy #SoftwareEngineering</span></span></code></pre></div><p>LinkedIn auto-generates the link preview card from the OG tags. The URL in the post body is visible but the card is what people actually click.</p><hr><h2 id="writing-a-new-post" tabindex="-1">Writing a New Post <a class="header-anchor" href="#writing-a-new-post" aria-label="Permalink to “Writing a New Post”">​</a></h2><p>The workflow from here:</p><ol><li>Create <code>docs/your-slug.md</code> with frontmatter: <code>title</code>, <code>date</code>, <code>description</code></li><li>Write the post</li><li><code>git add . &amp;&amp; git commit -m &quot;post: your title&quot; &amp;&amp; git push</code></li></ol><p>GitHub Actions builds the site, generates the RSS feed, deploys to GitHub Pages. Buffer polls the feed within the hour, picks up the new item, and queues the LinkedIn post. Nothing else required.</p><hr><h2 id="what-i-didn-t-do" tabindex="-1">What I Didn&#39;t Do <a class="header-anchor" href="#what-i-didn-t-do" aria-label="Permalink to “What I Didn&#39;t Do”">​</a></h2><p>I looked at direct LinkedIn API integration. The LinkedIn API requires OAuth with a user token, refresh token rotation, app approval for the <code>w_member_social</code> scope, and a server to handle the token exchange. For a static site with no backend, that&#39;s a lot of infrastructure to maintain for something Buffer already handles with four input fields.</p><p>I also looked at Zapier and Make. Both work, but both add a paid intermediary with their own failure modes. Buffer is already in the stack. Using it for RSS automation costs nothing extra.</p><p>The complexity budget matters. This solution has two failure points: GitHub Actions (near-zero failure rate) and Buffer&#39;s RSS polling (reliable within the hour). That&#39;s acceptable.</p><hr><p><em>Automation that survives without maintenance is the only automation worth building.</em></p>`,49)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
